import { IMessageComposer } from '@nitrots/nitro-renderer';

export class HighLowDeclineComposer implements IMessageComposer<Array<number>> {
    private _data: Array<number>;

    constructor() {
        // No payload needed; just signal DECLINE = 0
        this._data = [0];
    }

    public getMessageArray(): Array<number> {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
